function divide(a, b) {
  if (b === 0) {
    throw new Error('division by zero');
  }
  return a / b;
}

def divide(a, b):
  if b == 0:
    raise ValueError('division by zero')
  return a / b
result = divide(10, 0)

public int divide(int a, int b) throws Exception {
  if (b == 0) {
    throw new Exception("division by zero");
  }
  return a / b;
}

CREATE PROCEDURE DivideNumbers @a INT, @b INT AS
IF @b = 0
  THROW 50000, 'division by zero', 1;
SELECT @a / @b;
